example.code:
# policies/kubernetes/no-privileged.rego package kubernetes.admission
import rego.v1
deny contains msg if { input.request.kind.kind == "Pod" some container in input.request.object.spec.containers container.securityContext.privileged == true msg := sprintf("Container '%s' must not run as privileged", [container.name]) }
deny contains msg if { input.request.kind.kind == "Pod" some container in input.request.object.spec.initContainers container.securityContext.privileged == true msg := sprintf("Init container '%s' must not run as privileged", [container.name]) }

# policies/kubernetes/trusted-registry.rego
package kubernetes.admission

import rego.v1

trusted_registries := {
    "gcr.io/my-project",
    "docker.io/myorg",
    "ghcr.io/myorg"
}

deny contains msg if {
    input.request.kind.kind == "Pod"
    some container in input.request.object.spec.containers
    not any_trusted_registry(container.image)
    msg := sprintf("Container '%s' uses untrusted registry: %s", [container.name, container.image])
}

any_trusted_registry(image) if {
    some registry in trusted_registries
    startswith(image, registry)
}

# policies/kubernetes/no-privileged_test.rego
package kubernetes.admission

import rego.v1

test_deny_privileged_container if {
    result := deny with input as {
        "request": {
            "kind": {"kind": "Pod"},
            "object": {
                "spec": {
                    "containers": [{
                        "name": "nginx",
                        "securityContext": {"privileged": true}
                    }]
                }
            }
        }
    }
    count(result) > 0
}

test_allow_non_privileged_container if {
    result := deny with input as {
        "request": {
            "kind": {"kind": "Pod"},
            "object": {
                "spec": {
                    "containers": [{
                        "name": "nginx",
                        "securityContext": {"privileged": false}
                    }]
                }
            }
        }
    }
    count(result) == 0
}
